<template><div class="space-y-4"><div class="flex items-center justify-between"><h2 class="text-xl font-bold" style="color:#00f0ff">💾 备份恢复</h2><button @click="doBackup()" class="px-4 py-2 rounded-lg text-sm" style="background:linear-gradient(135deg,#00f0ff,#b700ff);color:#fff">立即备份</button></div><div class="grid grid-cols-3 gap-4"><div class="cyber-card rounded-xl p-4 text-center"><div class="text-xs" style="color:#a0a0cc">备份总数</div><div class="text-2xl font-bold" style="color:#00f0ff">{{backups.length}}</div></div><div class="cyber-card rounded-xl p-4 text-center"><div class="text-xs" style="color:#a0a0cc">总占用</div><div class="text-2xl font-bold" style="color:#ff2d95">4.2GB</div></div><div class="cyber-card rounded-xl p-4 text-center"><div class="text-xs" style="color:#a0a0cc">最近备份</div><div class="text-2xl font-bold" style="color:#b700ff">{{backups[0]?.time}}</div></div></div><div class="cyber-card rounded-xl overflow-hidden"><table class="w-full"><thead><tr style="background:#0d0d1a"><th class="px-4 py-3 text-left text-xs" style="color:#ff2d95">名称</th><th class="px-4 py-3 text-left text-xs" style="color:#ff2d95">时间</th><th class="px-4 py-3 text-left text-xs" style="color:#ff2d95">大小</th><th class="px-4 py-3 text-left text-xs" style="color:#ff2d95">类型</th><th class="px-4 py-3 text-left text-xs" style="color:#ff2d95">操作</th></tr></thead><tbody><tr v-for="b in backups" :key="b.id" class="border-t" style="border-color:#00f0ff10"><td class="px-4 py-3 text-sm" style="color:#e0e0ff">{{b.name}}</td><td class="px-4 py-3 text-sm" style="color:#a0a0cc">{{b.time}}</td><td class="px-4 py-3 text-sm" style="color:#00f0ff">{{b.size}}</td><td class="px-4 py-3"><span class="text-xs px-2 py-0.5 rounded" :style="{background:b.auto?'#b700ff20':'#00f0ff20',color:b.auto?'#b700ff':'#00f0ff'}">{{b.auto?'自动':'手动'}}</span></td><td class="px-4 py-3"><button class="text-xs px-2 py-1 rounded mr-1" style="color:#00f0ff;background:#00f0ff15">恢复</button><button class="text-xs px-2 py-1 rounded" style="color:#ff2d95;background:#ff2d9515">删除</button></td></tr></tbody></table></div></div></template>
<script setup lang="ts">
import {ref} from 'vue'
const backups=ref(Array.from({length:15},(_,i)=>{const d=new Date(Date.now()-i*864e5);return{id:i,name:'backup_'+d.toISOString().slice(0,10),time:d.toLocaleDateString('zh-CN'),size:Math.floor(Math.random()*500+100)+'MB',auto:i%3!==0}}))
function doBackup(){window.alert("备份已启动")}
</script>